const d = $input.first().json;
const history = JSON.parse(d.history_json || '[]');

// Build conversation context from DB history
let historialTexto = '';
if (history.length > 0) {
  const recientes = history.slice(-10);
  historialTexto = '\n\n[ConversaciГіn previa]\n' +
    recientes.map(m => (m.role === 'human' ? 'Cliente: ' : 'Asistente: ') + m.content).join('\n') +
    '\n[Fin conversaciГіn previa]';
}

return [{ json: {
  mensaje:        d.mensaje,
  numero:         d.numero,
  nombre:         d.nombre || '',
  fecha_contexto: d.fecha_contexto || '',
  prompt_extra:   historialTexto
}}];
